import moment from 'moment';
import { Zone, isValidZone } from './zone';

declare module 'moment' {
  interface Moment {
    tz(): string | undefined;
    tz(timezone: string, keepLocalTime?: boolean): moment.Moment;
    // zoneAbbr(): string;
    // zoneName(): string;
  }

  let defaultZone: Zone | null;

  const tz: MomentTimezone;
}

// export interface MomentZoneOffset {
