export interface MomentTimezone {
  (): moment.Moment;
  (timezone: string): moment.Moment;
  (date: number, timezone: string): moment.Moment;
  (date: number[], timezone: string): moment.Moment;
  (date: string, timezone: string): moment.Moment;
  (date: string, format: moment.MomentFormatSpecification, timezone: string): moment.Moment;
  (date: string, format: moment.MomentFormatSpecification, strict: boolean, timezone: string): moment.Moment;
  (date: string, format: moment.MomentFormatSpecification, language: string, timezone: string): moment.Moment;
  (
    date: string,
    format: moment.MomentFormatSpecification,
    language: string,
    strict: boolean,
    timezone: string
  ): moment.Moment;
  (date: Date, timezone: string): moment.Moment;
  (date: moment.Moment, timezone: string): moment.Moment;
  (date: any, timezone: string): moment.Moment;

  zone(timezone: string): Zone | null;

  // add(packedZoneString: string): void;
  // add(packedZoneString: string[]): void;

  // link(packedLinkString: string): void;
  // link(packedLinkString: string[]): void;

  // load(data: { version: string; links: string[]; zones: string[] }): void;

  names(): string[];
  // zonesForCountry<T extends true>(country: string, with_offset: T): T extends true ? MomentZoneOffset[] : never;
  // zonesForCountry<T extends false>(country: string, with_offset?: T): T extends false ? string[] : never;
  // zonesForCountry(country: string, with_offset?: boolean): MomentZoneOffset[] | string[];
  // countries(): string[];
  guess(ignoreCache?: boolean): string;
  needsOffset(mom: moment.Moment): boolean;

  setDefault(timezone?: string): typeof moment;
  // dataVersion: string;
}

/**
 * @private
 */
interface InternalMoment extends moment.Moment {
  _a?: [year: number, month: number, date: number, hour: number, minute: number, second: number, ms: number];
  _d: Date;
  /** input 为 string 时，对应的 Format */
  _f?: string;
  /** input，初始化参数 */
  _i?: unknown;
  _isUTC: boolean;
  /** 表示时区偏移量的整数。它指示当前日期和时间与 UTC 的差异，以分钟为单位。 */
  _tzm?: unknown;
  _z?: Zone | null;
}

function needsOffset(m: InternalMoment) {
  const isUnixTimestamp = m._f === 'X' || m._f === 'x';
  return !!(m._a && m._tzm === undefined && !isUnixTimestamp);
}

function updateOffset(mom: InternalMoment, keepTime?: boolean) {
  if (!mom.isValid()) return;
  if (mom._z === undefined) {
    const defaultZone = moment.defaultZone;
    if (defaultZone && needsOffset(mom) && !mom._isUTC) {
      mom._d = (moment.utc(mom._a) as InternalMoment)._d;
      mom.utc().add(defaultZone.parse(mom), 'minutes');
    }
    mom._z = defaultZone;
  }
  if (mom._z) {
    const offset = -mom._z.utcOffset(mom)!;
    // mom._z will be cleared after calling `utcOffset()`
    const z = mom._z;
    mom.utcOffset(offset, keepTime);
    mom._z = z;
  }
}

function fnTz(this: InternalMoment): string | undefined;
function fnTz(this: InternalMoment, timezone: string, keepLocalTime?: boolean): moment.Moment;
function fnTz(this: InternalMoment, timezone?: string, keepLocalTime?: boolean) {
  if (!timezone) return this._z?.name;
  if (this._z && this._z.name === timezone) return this;
  if (isValidZone(timezone)) {
    this._z = new Zone(timezone);
    updateOffset(this, keepLocalTime);
  } else {
    console.error(`Intl Timezone has no data for ${timezone}`);
  }
  return this as moment.Moment;
}

function abbrWrap(old: moment.Moment['zoneAbbr']) {
  return function (this: InternalMoment) {
    if (this._z) return this._z.abbr(this);
    return old.call(this);
  } as moment.Moment['zoneAbbr'];
}

function resetZoneWrap(old: moment.Moment['utc']) {
  return function (this: InternalMoment, keepLocalTime) {
    this._z = null;
    return old.call(this, keepLocalTime);
  } as moment.Moment['utc'];
}

function resetZoneWrap2(old: moment.Moment['utcOffset']) {
  return function (this: InternalMoment) {
    if (arguments.length > 0) this._z = null;
    return old.apply(this, arguments as unknown as Parameters<moment.Moment['utcOffset']>);
  } as unknown as moment.Moment['utcOffset'];
}

const getNames: MomentTimezone['names'] = () => Intl.supportedValuesOf('timeZone');
const guess: MomentTimezone['guess'] = () => Intl.DateTimeFormat().resolvedOptions().timeZone;
const setDefault: MomentTimezone['setDefault'] = (name) => {
  moment.defaultZone = isValidZone(name) ? new Zone(name) : null;
  return moment;
};

type StaticFunctions = Pick<MomentTimezone, keyof MomentTimezone>;

function attachMoment() {
  // @ts-expect-error Internal property
  const { fn, momentProperties } = moment;
  momentProperties.push('_z');
  momentProperties.push('_a');

  fn.tz = fnTz;
  fn.zoneAbbr = abbrWrap(fn.zoneAbbr);
  fn.zoneName = abbrWrap(fn.zoneName);
  fn.utc = resetZoneWrap(fn.utc);
  fn.local = resetZoneWrap(fn.local);
  fn.utcOffset = resetZoneWrap2(fn.utcOffset);

  function tz(input: unknown) {
    const args = Array.prototype.slice.call(arguments, 0, -1);
    const name = arguments[arguments.length - 1];
    const out = moment.utc.apply(null, args as unknown as Parameters<(typeof moment)['utc']>);

    if (!moment.isMoment(input) && needsOffset(out as InternalMoment)) {
      if (isValidZone(name)) {
        const zone = new Zone(name);
        out.add(zone.parse(out), 'minutes');
      } else {
        console.error(`Intl Timezone has no data for ${name}`);
      }
    }

    out.tz(name);
    return out;
  }

  moment.defaultZone = null;
  tz.zone = (timezone: string) => (isValidZone(timezone) ? new Zone(timezone) : null);
  tz.needsOffset = needsOffset;
  tz.names = getNames;
  tz.guess = guess;
  tz.setDefault = setDefault;

  Object.assign(moment, {
    updateOffset,
    tz: tz satisfies StaticFunctions,
  });
}

if (!moment.tz) {
  attachMoment();
}

export default moment;
