import moment from 'moment';
import { predictV3Strategy as getUTCMilliseconds } from './utc';

export class Zone {
  constructor(readonly name: string) {
    if (!isValidZone(name)) throw new Error(`${name} is an invalid zone`);
  }

  abbr(mom: moment.Moment): string | undefined {
    const parts = getDateTimeFormat(this.name).formatToParts(mom.valueOf());
    return parts.find((part) => part.type === 'timeZoneName')?.value;
  }

  utcOffset(mom: moment.Moment): number | undefined;
  utcOffset(mom: Date | number): number;
  utcOffset(mom: moment.Moment | Date | number): number | undefined {
    if (moment.isMoment(mom) && !mom.isValid()) return;
    const dtf = getDateTimeFormatWithCache(this.name);
    const momValue = mom.valueOf();
    const utc = getUTCMilliseconds(dtf, momValue);
    return Math.floor((momValue - utc) / 60000);
  }

  // find the right offset a given local time. The o input is our guess, which determines which
  // offset we'll pick in ambiguous cases (e.g. there are two 3 AMs b/c Fallback DST)
  // https://github.com/moment/luxon/blob/f257940093dca8efa976e142e0f33ed3620425ed/src/datetime.js#L99-L124
  parse(localTS: moment.Moment | Date | number): number {
    localTS = +localTS;
    const utcOffset = this.utcOffset.bind(this);
    const o = utcOffset(Date.now());
    // Our UTC time is just a guess because our offset is just a guess
    let utcGuess = localTS + o * 60 * 1000;
    // Test whether the zone matches the offset for this ts
    const o2 = utcOffset(utcGuess);
    // If so, offset didn't change and we're done
    if (o === o2) {
      return o;
    }
    // If not, change the ts by the difference in the offset
    utcGuess += (o2 - o) * 60 * 1000;
    // If that gives us the local time we want, we're done
    const o3 = utcOffset(utcGuess);
    if (o2 === o3) {
      return o2;
    }
    // If it's different, we're in a hole time. The offset has changed, but the we don't adjust the time
    return Math.min(o2, o3);
  }
}

export function getDateTimeFormat(timezone: string, options: Intl.DateTimeFormatOptions = {}) {
  const timeZoneName = options.timeZoneName || 'short';
  return new Intl.DateTimeFormat('en-US', {
    hour12: false,
    timeZone: timezone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    timeZoneName,
  });
}

const validZones = new Set<string>();
export function isValidZone(zone: string | undefined): zone is string {
  if (!zone) return false;
  if (validZones.has(zone)) return true;
  try {
    getDateTimeFormatWithCache(zone).format();
    validZones.add(zone);
    return true;
  } catch {
    return false;
  }
}

const dtfCache: Record<string, Intl.DateTimeFormat> = {};
export function getDateTimeFormatWithCache(timezone: string) {
  if (dtfCache[timezone]) return dtfCache[timezone];
  const dtf = getDateTimeFormat(timezone);
  dtfCache[timezone] = dtf;
  return dtf;
}
