import moment from 'moment';

export type GetUTCMillisecondsFn = (dtf: Intl.DateTimeFormat, date: Date | number) => number;

/**
 * credits [dayjs](https://github.com/iamkun/dayjs/blob/0fb4acf225f7c6991b4ae5b2ed11f166c7d73cb3/src/plugin/timezone/index.js#L45-L67)
 */
export const typeToPosStrategy: GetUTCMillisecondsFn = (() => {
  const typeToPos: Partial<Record<keyof Intl.DateTimeFormatPartTypesRegistry, number>> = {
    year: 0,
    month: 1,
    day: 2,
    hour: 3,
    minute: 4,
    second: 5,
  };
  return (dtf, date) => {
    const formatResult = dtf.formatToParts(date);
    const filled: string[] = [];
    for (let i = 0; i < formatResult.length; i++) {
      const { type, value } = formatResult[i];
      const pos = typeToPos[type];
      if (pos !== undefined) {
        filled[pos] = value;
      }
    }
    const hour = filled[3];
    // Workaround for the same behavior in different node version
    // https://github.com/nodejs/node/issues/33027
    const fixedHour = hour === '24' ? '00' : hour;
    return moment.utc(`${filled[0]}-${filled[1]}-${filled[2]} ${fixedHour}:${filled[4]}:${filled[5]}.000`).valueOf();
  };
})();

export const fromEntriesStrategy: GetUTCMillisecondsFn = (dtf, date) => {
  const formatResult = dtf.formatToParts(date);
  const partDict: Partial<Record<keyof Intl.DateTimeFormatPartTypesRegistry, string>> = Object.fromEntries(
    formatResult.map(({ type, value }) => [type, value])
  );
  // Workaround for the same behavior in different node version
  // https://github.com/nodejs/node/issues/33027
  const fixedHour = partDict.hour === '24' ? '00' : partDict.hour;
  return moment
    .utc(`${partDict.year}-${partDict.month}-${partDict.day} ${fixedHour}:${partDict.minute}:${partDict.second}.000`)
    .valueOf();
};

export const predictStrategy: GetUTCMillisecondsFn = (() => {
  const partIndexDict = {
    year: 0,
    month: 0,
    day: 0,
    hour: 0,
    minute: 0,
    second: 0,
  } satisfies Partial<Record<keyof Intl.DateTimeFormatPartTypesRegistry, number>>;
  return (dtf, date) => {
    const formatResult = dtf.formatToParts(date);
    formatResult.forEach(({ type }, index) => {
      if (type in partIndexDict) partIndexDict[type as keyof typeof partIndexDict] = index;
    });
    const hour = formatResult[partIndexDict.hour].value;
    // Workaround for the same behavior in different node version
    // https://github.com/nodejs/node/issues/33027
    const fixedHour = hour === '24' ? '00' : hour;
    return moment
      .utc(
        `${formatResult[partIndexDict.year].value}-${formatResult[partIndexDict.month].value}-${
          formatResult[partIndexDict.day].value
        } ${fixedHour}:${formatResult[partIndexDict.minute].value}:${formatResult[partIndexDict.second].value}.000`
      )
      .valueOf();
  };
})();

export const predictV2Strategy: GetUTCMillisecondsFn = (() => {
  const partIndexDict = {
    year: 0,
    month: 0,
    day: 0,
    hour: 0,
    minute: 0,
    second: 0,
  } satisfies Partial<Record<keyof Intl.DateTimeFormatPartTypesRegistry, number>>;
  return (dtf, date) => {
    const formatResult = dtf.formatToParts(date);
    formatResult.forEach(({ type }, index) => {
      if (type in partIndexDict) partIndexDict[type as keyof typeof partIndexDict] = index;
    });
    const hour = formatResult[partIndexDict.hour].value;
    // Workaround for the same behavior in different node version
    // https://github.com/nodejs/node/issues/33027
    const fixedHour = hour === '24' ? 0 : Number(hour);
    return moment
      .utc([
        Number(formatResult[partIndexDict.year].value),
        Number(formatResult[partIndexDict.month].value) - 1,
        Number(formatResult[partIndexDict.day].value),
        fixedHour,
        Number(formatResult[partIndexDict.minute].value),
        Number(formatResult[partIndexDict.second].value),
      ])
      .valueOf();
  };
})();

export const predictV3Strategy: GetUTCMillisecondsFn = (() => {
  const partIndexDict = {
    year: 0,
    month: 0,
    day: 0,
    hour: 0,
    minute: 0,
    second: 0,
  } satisfies Partial<Record<keyof Intl.DateTimeFormatPartTypesRegistry, number>>;
  return function boost(dtf, date) {
    const formatResult = dtf.formatToParts(date);
    formatResult.forEach(({ type }, index) => {
      if (type in partIndexDict) partIndexDict[type as keyof typeof partIndexDict] = index;
    });
    const hour = formatResult[partIndexDict.hour].value;
    // Workaround for the same behavior in different node version
    // https://github.com/nodejs/node/issues/33027
    const fixedHour = hour === '24' ? 0 : Number(hour);
    return Date.UTC(
      Number(formatResult[partIndexDict.year].value),
      Number(formatResult[partIndexDict.month].value) - 1,
      Number(formatResult[partIndexDict.day].value),
      fixedHour,
      Number(formatResult[partIndexDict.minute].value),
      Number(formatResult[partIndexDict.second].value)
    ).valueOf();
  };
})();

export const predictWithCacheStrategy: GetUTCMillisecondsFn = (() => {
  const partIndexDictCache = {
    /** is initialized */
    _: false as boolean,
    year: 0,
    month: 0,
    day: 0,
    hour: 0,
    minute: 0,
    second: 0,
  } satisfies Partial<Record<keyof Intl.DateTimeFormatPartTypesRegistry, number>> & { _: boolean };
  return (dtf, date) => {
    const formatResult = dtf.formatToParts(date);
    if (!partIndexDictCache._) {
      formatResult.forEach(({ type }, index) => {
        if (type in partIndexDictCache)
          partIndexDictCache[type as Extract<keyof typeof partIndexDictCache, typeof type>] = index;
      });
      partIndexDictCache._ = true;
    }
    const hour = formatResult[partIndexDictCache.hour].value;
    // Workaround for the same behavior in different node version
    // https://github.com/nodejs/node/issues/33027
    const fixedHour = hour === '24' ? '00' : hour;
    return moment
      .utc(
        `${formatResult[partIndexDictCache.year].value}-${formatResult[partIndexDictCache.month].value}-${
          formatResult[partIndexDictCache.day].value
        } ${fixedHour}:${formatResult[partIndexDictCache.minute].value}:${
          formatResult[partIndexDictCache.second].value
        }.000`
      )
      .valueOf();
  };
})();
